import axios from 'axios';

const API_BASE_URL = process.env.VUE_APP_API_URL || 'http://localhost:3000';

// Create axios instance with interceptors
const adminApi = axios.create({
    baseURL: API_BASE_URL,
    timeout: 10000
});

// Request interceptor to add auth token
adminApi.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Response interceptor for error handling
adminApi.interceptors.response.use(
    (response) => response,
    (error) => {
        if (error.response?.status === 401) {
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            window.location.href = '/login';
        }
        return Promise.reject(error);
    }
);

// Admin API functions
export const adminAPI = {
    // Get all users with pagination and search
    getAllUsers: async (page = 1, limit = 10, search = '') => {
        try {
            const response = await adminApi.get('/api/admin/users', {
                params: { page, limit, search }
            });
            return response.data;
        } catch (error) {
            console.error('Error getting all users:', error);
            throw error;
        }
    },

    // Get system statistics
    getSystemStats: async () => {
        try {
            const response = await adminApi.get('/api/admin/stats');
            return response.data;
        } catch (error) {
            console.error('Error getting system stats:', error);
            throw error;
        }
    },

    // Get user details by ID
    getUserById: async (userId) => {
        try {
            const response = await adminApi.get(`/api/admin/users/${userId}`);
            return response.data;
        } catch (error) {
            console.error('Error getting user by ID:', error);
            throw error;
        }
    },

    // Update user role
    updateUserRole: async (userId, role) => {
        try {
            const response = await adminApi.patch(`/api/admin/users/${userId}/role`, {
                role
            });
            return response.data;
        } catch (error) {
            console.error('Error updating user role:', error);
            throw error;
        }
    },

    // Delete user
    deleteUser: async (userId) => {
        try {
            const response = await adminApi.delete(`/api/admin/users/${userId}`);
            return response.data;
        } catch (error) {
            console.error('Error deleting user:', error);
            throw error;
        }
    }
};

export default adminAPI;
